exercises.correction:
class Program {
    static int Somme(int a, int b) { return a + b; }
    static void Main() {
        System.Console.WriteLine(Somme(3, 4));
    }
}

class Program {
    static void Main() {
        int[] t = {5, 10, 15};
        foreach (int x in t) System.Console.WriteLine(x);
    }
}

class Program {
    static void Main() {
        int[] t = {1, 2, 3, 4, 5};
        int total = 0;
        foreach (int x in t) total += x;
        System.Console.WriteLine(total);
    }
}
